74	// GetBeadSnapshotsForProject implements ddxgraphql.StateProvider. It opens
75	// exactly one project's bead store — iteration over other projects is not
76	// performed for any reason, so the cross-project loop cost is avoided for the
77	// common per-project bead list.
78	func (s *ServerState) GetBeadSnapshotsForProject(projectID, status, label, search string) []ddxgraphql.BeadSnapshot {
79		if projectID == "" {
80			return nil
81		}
82		proj, ok := s.GetProjectByID(projectID)
83		if !ok {
84			return nil
85		}
86		pred := beadFilterPredicate(status, label, search)
87		return s.beadSnapshotsForProjectEntry(proj, pred)
88	}
