118	// beadFilterPredicate returns a predicate suitable for bead.Store.ReadAllFiltered
119	// that applies status/label/search filters. A nil return means "match all".
120	func beadFilterPredicate(status, label, search string) func(bead.Bead) bool {
121		if status == "" && label == "" && search == "" {
122			return nil
123		}
124		q := strings.ToLower(search)
125		return func(b bead.Bead) bool {
126			if status != "" && b.Status != status {
127				return false
128			}
129			if label != "" && !containsString(b.Labels, label) {
130				return false
131			}
132			if q != "" {
133				if !strings.Contains(strings.ToLower(b.ID), q) && !strings.Contains(strings.ToLower(b.Title), q) {
134					return false
135				}
136			}
137			return true
138		}
139	}
