141	// GetBeadSnapshot implements ddxgraphql.StateProvider.
142	func (s *ServerState) GetBeadSnapshot(id string) (*ddxgraphql.BeadSnapshot, bool) {
143		if id == "" {
144			return nil, false
145		}
146	
147		if loc, ok := s.lookupBeadLocation(id); ok {
148			proj := ProjectEntry{ID: loc.ProjectID, Path: loc.ProjectPath}
149			if snap, ok := readBeadSnapshotFromProject(proj, id); ok {
150				return snap, true
151			}
152			s.forgetBeadLocation(id)
153		}
154	
155		for _, proj := range s.GetProjects() {
156			if snap, ok := readBeadSnapshotFromProject(proj, id); ok {
157				s.rememberBeadLocation(id, proj)
158				return snap, true
159			}
160		}
161		return nil, false
162	}
