164	func (s *ServerState) rememberBeadLocation(id string, proj ProjectEntry) {
165		if id == "" || proj.ID == "" || proj.Path == "" {
166			return
167		}
168		s.beadIndexMu.Lock()
169		defer s.beadIndexMu.Unlock()
170		if s.beadIndex == nil {
171			s.beadIndex = make(map[string]beadIndexEntry)
172		}
173		s.beadIndex[id] = beadIndexEntry{ProjectID: proj.ID, ProjectPath: proj.Path}
174	}
