257	// GetWorkersGraphQL implements ddxgraphql.StateProvider.
258	// Reads worker records from disk and returns them as GraphQL Worker values.
259	// If projectID is non-empty, only workers for that project are returned.
260	// An unknown projectID returns an empty list (not an error).
261	//
262	// WorkerRecord stores the project's filesystem path in ProjectRoot, but the
263	// GraphQL argument is a project id (e.g. proj-96d7ea83). Resolve the id to a
264	// path via the project registry before filtering so the two representations
265	// match; previously this compared id→path directly and filtered out every
266	// worker on per-project queries.
267	func (s *ServerState) GetWorkersGraphQL(projectID string) []*ddxgraphql.Worker {
268		if s.workingDir == "" {
269			return nil
270		}
271		expectedPath := ""
272		if projectID != "" {
273			proj, ok := s.GetProjectByID(projectID)
274			if !ok {
275				return nil
276			}
277			expectedPath = proj.Path
278		}
279		workersDir := filepath.Join(s.workingDir, ".ddx", "workers")
280		entries, err := os.ReadDir(workersDir)
281		if err != nil {
282			return nil
283		}
284		var out []*ddxgraphql.Worker
285		for _, entry := range entries {
286			if !entry.IsDir() {
287				continue
288			}
289			data, err := os.ReadFile(filepath.Join(workersDir, entry.Name(), "status.json"))
290			if err != nil {
291				continue
292			}
293			var rec WorkerRecord
294			if err := json.Unmarshal(data, &rec); err != nil {
295				continue
296			}
297			if expectedPath != "" && rec.ProjectRoot != expectedPath {
298				continue
299			}
300			out = append(out, workerFromRecord(rec))
301		}
302		// Newest first.
303		sort.Slice(out, func(i, j int) bool {
304			si, sj := out[i].StartedAt, out[j].StartedAt
305			if si == nil || sj == nil {
306				return si != nil
307			}
308			ti, _ := time.Parse(time.RFC3339, *si)
309			tj, _ := time.Parse(time.RFC3339, *sj)
310			return ti.After(tj)
311		})
312		return out
313	}
