394	// workerFromRecord converts a WorkerRecord to the GraphQL Worker type.
395	func workerFromRecord(rec WorkerRecord) *ddxgraphql.Worker {
396		attempts := rec.Attempts
397		successes := rec.Successes
398		failures := rec.Failures
399		w := &ddxgraphql.Worker{
400			ID:           rec.ID,
401			Kind:         rec.Kind,
402			State:        rec.State,
403			ProjectRoot:  rec.ProjectRoot,
404			Attempts:     &attempts,
405			Successes:    &successes,
406			Failures:     &failures,
407			RecentEvents: []*ddxgraphql.WorkerRecentEvent{},
408		}
409		if rec.Status != "" {
410			w.Status = &rec.Status
411		}
412		if rec.Harness != "" {
413			w.Harness = &rec.Harness
414		}
415		if rec.Provider != "" {
416			w.Provider = &rec.Provider
417		}
418		if rec.Model != "" {
419			w.Model = &rec.Model
420		}
421		if rec.Effort != "" {
422			w.Effort = &rec.Effort
423		}
424		if rec.Once {
425			b := true
426			w.Once = &b
427		}
428		if rec.PollInterval != "" {
429			w.PollInterval = &rec.PollInterval
430		}
431		if !rec.StartedAt.IsZero() {
432			s := rec.StartedAt.UTC().Format(time.RFC3339)
433			w.StartedAt = &s
434		}
435		if !rec.FinishedAt.IsZero() {
436			s := rec.FinishedAt.UTC().Format(time.RFC3339)
437			w.FinishedAt = &s
438		}
439		if rec.Error != "" {
440			w.Error = &rec.Error
441		}
442		if rec.StdoutPath != "" {
443			w.StdoutPath = &rec.StdoutPath
444		}
445		if rec.SpecPath != "" {
446			w.SpecPath = &rec.SpecPath
447		}
448		if rec.CurrentBead != "" {
449			w.CurrentBead = &rec.CurrentBead
450		}
451		if rec.LastError != "" {
452			w.LastError = &rec.LastError
453		}
454		if rec.LastResult != nil {
455			w.LastResult = workerResultFromRecord(rec.LastResult)
456		}
457		if rec.CurrentAttempt != nil {
458			w.CurrentAttempt = currentAttemptFromRecord(rec.CurrentAttempt)
459		}
460		for _, p := range rec.RecentPhases {
461			pt := p // copy
462			w.RecentPhases = append(w.RecentPhases, &ddxgraphql.PhaseTransition{
463				Phase:    pt.Phase,
464				Ts:       pt.TS.UTC().Format(time.RFC3339),
465				PhaseSeq: pt.PhaseSeq,
466			})
467		}
468		for _, e := range rec.Lifecycle {
469			ev := e
470			gqlEvent := &ddxgraphql.WorkerLifecycleEvent{
471				Action:    ev.Action,
472				Actor:     ev.Actor,
473				Timestamp: ev.Timestamp.UTC().Format(time.RFC3339),
474			}
475			if ev.Detail != "" {
476				gqlEvent.Detail = &ev.Detail
477			}
478			if ev.BeadID != "" {
479				gqlEvent.BeadID = &ev.BeadID
480			}
481			w.LifecycleEvents = append(w.LifecycleEvents, gqlEvent)
482		}
483		if rec.LastAttempt != nil {
484			w.LastAttempt = lastAttemptFromRecord(rec.LastAttempt)
485		}
486		if rec.LandSummary != nil {
487			w.LandSummary = landSummaryFromRecord(rec.LandSummary)
488		}
489		return w
490	}
