673	// readProjectSessions reads monthly session shards for one project and maps to graphql types.
674	func readProjectSessions(proj ProjectEntry, startedAfter, startedBefore *time.Time) []*ddxgraphql.AgentSession {
675		logDir := agent.SessionLogDirForWorkDir(proj.Path)
676		entries, err := agent.ReadSessionIndex(logDir, agent.SessionIndexQuery{
677			StartedAfter:  startedAfter,
678			StartedBefore: startedBefore,
679			DefaultRecent: startedAfter == nil && startedBefore == nil,
680		})
681		if err != nil {
682			return nil
683		}
684		out := make([]*ddxgraphql.AgentSession, 0, len(entries))
685		for _, e := range entries {
686			sess := agentSessionFromIndex(proj.ID, e)
687			out = append(out, sess)
688		}
