692	func agentSessionFromIndex(projectID string, e agent.SessionIndexEntry) *ddxgraphql.AgentSession {
693		sess := &ddxgraphql.AgentSession{
694			ID:         e.ID,
695			ProjectID:  projectID,
696			Harness:    e.Harness,
697			Model:      e.Model,
698			Effort:     e.Effort,
699			DurationMs: e.DurationMS,
700			StartedAt:  e.StartedAt.UTC().Format(time.RFC3339),
701		}
702	
703		// Derive status and outcome from exit code / error.
704		if e.ExitCode != 0 || e.Outcome == "failure" {
705			sess.Status = "failed"
706			outcome := "failure"
707			sess.Outcome = &outcome
708			if e.Detail != "" {
709				sess.Detail = &e.Detail
710			}
711		} else {
712			sess.Status = "completed"
713			outcome := "success"
714			sess.Outcome = &outcome
715		}
716	
717		// EndedAt = StartedAt + duration.
718		if !e.EndedAt.IsZero() {
719			endedAt := e.EndedAt.UTC().Format(time.RFC3339)
720			sess.EndedAt = &endedAt
721		} else if e.DurationMS > 0 {
722			endedAt := e.StartedAt.Add(time.Duration(e.DurationMS) * time.Millisecond).UTC().Format(time.RFC3339)
723			sess.EndedAt = &endedAt
724		}
725	
726		if e.CostUSD > 0 {
727			sess.Cost = &e.CostUSD
728		}
729	
730		// Token breakdown.
731		if e.InputTokens > 0 || e.OutputTokens > 0 || e.Tokens > 0 {
732			prompt := e.InputTokens
733			completion := e.OutputTokens
734			total := e.Tokens
735			sess.Tokens = &ddxgraphql.TokenUsage{
736				Prompt:     &prompt,
737				Completion: &completion,
738				Total:      &total,
739			}
740		}
741	
742		if e.BeadID != "" {
743			sess.BeadID = &e.BeadID
744		}
745		if e.WorkerID != "" {
746			sess.WorkerID = &e.WorkerID
747		}
748		if e.NativeLogRef != "" {
749			sess.StdoutPath = &e.NativeLogRef
750		}
751		if e.BaseRev != "" {
752			sess.BaseRev = &e.BaseRev
753		}
754		if e.ResultRev != "" {
755			sess.ResultRev = &e.ResultRev
756		}
757		return sess
758	}
